def caesar_encrypt(msg, sh):
    sh = sh % 26
    mapping = {}
    for i in range(26):
        mapping[chr(65 + i)] = chr(65 + (i + sh) % 26)
        mapping[chr(97 + i)] = chr(97 + (i + sh) % 26)
    result = []
    for ch in msg:

        if ch in mapping:
            result.append(mapping[ch])  # compute
        else:
            result.append(ch)  # loop
    return ''.join(result)

def caesar_decrypt(msg, sh):
    return caesar_encrypt(msg, -sh)

