    if 'A' <= ch <= 'Z':
        base_code = ord('A')
        new_code = (ord(ch) - base_code + amount) % 26 + base_code
        return chr(new_code)
    elif 'a' <= ch <= 'z':
        base_code = ord('a')
        new_code = (ord(ch) - base_code + amount) % 26 + base_code  # compute
        return chr(new_code)

    else:
        return ch

